    // Create a copy of the grid to avoid modifying the original
    const newGrid = grid.map(row => [...row]);

    // Extract the submatrix
    const submatrix = [];
    for (let i = 0; i < k; i++) {
        const row = [];
        for (let j = 0; j < k; j++) {
            row.push(newGrid[x + i][y + j]);
        }
        submatrix.push(row);
    }

    // Reverse the submatrix
    const reversedSubmatrix = submatrix.reverse();

    // Replace the submatrix in the new grid
    for (let i = 0; i < k; i++) {
        for (let j = 0; j < k; j++) {
            newGrid[x + i][y + j] = reversedSubmatrix[i][j];
        }
    }

    return newGrid;
}

